@namespace Lumeo

@{
    var subContext = new DropdownMenuSubContext(
        _open,
        EventCallback.Factory.Create<bool>(this, SetOpen),
        _wrapperId,
        _triggerId,
        _contentId,
        EventCallback.Factory.Create(this, CloseTree),
        ScheduleClose,
        CancelClose);
}

<CascadingValue Value="subContext" IsFixed="false">
    <div id="@_wrapperId" class="relative" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext? RootContext { get; set; }
    [CascadingParameter] public DropdownMenuSubContext? ParentSubContext { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _open;
    private readonly string _wrapperId = LumeoIds.New("dropdown-sub");
    internal readonly string _triggerId = LumeoIds.New("dropdown-sub-trigger");
    internal readonly string _contentId = LumeoIds.New("dropdown-sub-content");

    private CancellationTokenSource? _closeCts;

    private async Task SetOpen(bool value)
    {
        if (_open == value) return;
        _open = value;
        await InvokeAsync(StateHasChanged);
    }

    private async Task CloseTree()
    {
        await SetOpen(false);
        if (ParentSubContext is not null)
        {
            await ParentSubContext.CloseTree.InvokeAsync();
        }
        else if (RootContext is not null)
        {
            await RootContext.SetOpen.InvokeAsync(false);
        }
    }

    private void CancelClose()
    {
        try { _closeCts?.Cancel(); } catch (ObjectDisposedException) { }
        _closeCts?.Dispose();
        _closeCts = null;
    }

    private void ScheduleClose()
    {
        CancelClose();
        _closeCts = new CancellationTokenSource();
        var token = _closeCts.Token;
        _ = Task.Run(async () =>
        {
            try
            {
                await Task.Delay(200, token);
            }
            catch (TaskCanceledException) { return; }
            if (token.IsCancellationRequested) return;
            await InvokeAsync(async () => await SetOpen(false));
        });
    }

    public record DropdownMenuSubContext(
        bool IsOpen,
        EventCallback<bool> SetOpen,
        string WrapperId,
        string TriggerId,
        string ContentId,
        EventCallback CloseTree,
        Action ScheduleClose,
        Action CancelClose);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (SubContext.IsOpen)
{
    <div id="@SubContext.ContentId"
         role="menu"
         aria-orientation="vertical"
         class="@CssClass"
         tabindex="-1"
         @onkeydown="HandleKeyDown"
         @onmouseenter="HandleMouseEnter"
         @onmouseleave="HandleMouseLeave"
         @onmousedown:stopPropagation="true"
         @ontouchstart:stopPropagation="true"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public DropdownMenuSub.DropdownMenuSubContext SubContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _positioned;
    private int _focusedIndex = -1;

    private string CssClass => $"fixed z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/60 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in {Class}".Trim();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (SubContext.IsOpen && !_positioned)
        {
            await PositionWithFlip();
            _positioned = true;
            _focusedIndex = -1;
        }
        else if (!SubContext.IsOpen && _positioned)
        {
            await Cleanup();
        }
    }

    private async Task PositionWithFlip()
    {
        var side = "right";
        try
        {
            var triggerRect = await Interop.GetElementRect(SubContext.TriggerId);
            var viewport = await Interop.GetViewportSize();
            // Estimate content width; flip if not enough room on the right (use 200px as conservative width).
            if (triggerRect is not null && triggerRect.X + triggerRect.Width + 200 > viewport.Width)
            {
                side = "left";
            }
        }
        catch (JSDisconnectedException) { }

        await Interop.PositionFixed(SubContext.ContentId, SubContext.TriggerId, "start", false, side);
    }

    private async Task HandleMouseEnter()
    {
        SubContext.CancelClose();
        await Task.CompletedTask;
    }

    private void HandleMouseLeave()
    {
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await SubContext.CloseTree.InvokeAsync();
                break;
            case "ArrowLeft":
                SubContext.CancelClose();
                await SubContext.SetOpen.InvokeAsync(false);
                try { await Interop.FocusElement(SubContext.TriggerId); } catch (JSDisconnectedException) { }
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(SubContext.ContentId); } catch (JSDisconnectedException) { }
        _positioned = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_positioned) await Cleanup();
    }
}

@namespace Lumeo

<button id="@SubContext.TriggerId"
        type="button"
        role="menuitem"
        tabindex="-1"
        class="@CssClass"
        data-state="@(SubContext.IsOpen ? "open" : "closed")"
        aria-haspopup="menu"
        aria-expanded="@SubContext.IsOpen.ToString().ToLower()"
        aria-controls="@SubContext.ContentId"
        disabled="@Disabled"
        @onclick="HandleClick"
        @onmouseenter="HandleMouseEnter"
        @onmouseleave="HandleMouseLeave"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
    @ChildContent
    <Blazicon Svg="Lucide.ChevronRight" class="ml-auto h-4 w-4" />
</button>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public DropdownMenuSub.DropdownMenuSubContext SubContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 min-h-11 sm:min-h-0 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground data-[state=open]:bg-accent data-[state=open]:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed {Class}".Trim();

    private async Task HandleClick()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        await SubContext.SetOpen.InvokeAsync(!SubContext.IsOpen);
    }

    private async Task HandleMouseEnter()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        if (!SubContext.IsOpen)
        {
            await SubContext.SetOpen.InvokeAsync(true);
        }
    }

    private void HandleMouseLeave()
    {
        if (!SubContext.IsOpen) return;
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowRight":
            case "Enter":
            case " ":
                SubContext.CancelClose();
                if (!SubContext.IsOpen)
                {
                    await SubContext.SetOpen.InvokeAsync(true);
                }
                // Defer focus until SubContent renders.
                _ = InvokeAsync(async () =>
                {
                    await Task.Delay(20);
                    try
                    {
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, 0);
                    }
                    catch (JSDisconnectedException) { }
                });
                break;
        }
    }
}

@namespace Lumeo

@* The `group` class + `data-state` attribute let consumers rotate a chevron on open with
   `group-data-[state=open]:rotate-180` on any descendant icon — no EventCallbacks or bindings needed. *@
<div id="@_triggerId"
     class="@CssClass"
     role="button"
     data-state="@(Context.IsOpen ? "open" : "closed")"
     aria-haspopup="menu"
     aria-expanded="@Context.IsOpen.ToString().ToLower()"
     aria-controls="@Context.ContentId"
     @onclick="Toggle"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public DropdownMenu.DropdownMenuContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    internal string TriggerId => _triggerId;
    private readonly string _triggerId = LumeoIds.New("dropdown-trigger");

    private string CssClass => $"group inline-flex {Class}".Trim();

    private async Task Toggle() => await Context.SetOpen.InvokeAsync(!Context.IsOpen);
}
